import"./hoisted.2daoxv0f.js";document.addEventListener("DOMContentLoaded",()=>{const d=document.querySelectorAll("sup a[data-footnote-ref]");let i=0;d.forEach(n=>{const s=n.getAttribute("href")?.substring(1);if(!s)return;const c=document.getElementById(s);if(c){const e=document.createElement("div");e.className="sidenote",i%2===0?e.classList.add("right"):e.classList.add("left"),i++,e.innerHTML=c.innerHTML;const r=e.querySelector("[data-footnote-backref]");r&&r.remove();const o=e.querySelector("p");o?o.innerHTML="* "+o.innerHTML:e.innerHTML="* "+e.innerHTML;const t=n.closest("p, blockquote, li");if(t){t.style.position="relative",t.appendChild(e);const l=t.getBoundingClientRect(),a=n.getBoundingClientRect();e.style.top=a.top-l.top+"px"}}})});
